import React, { useState } from 'react';

const EditPurchase = ({ purchase, handleUpdate }) => {
  const [updatedPurchase, setUpdatedPurchase] = useState({ ...purchase });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setUpdatedPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    handleUpdate(updatedPurchase);
  };

  return (
    <div className="edit-purchase-container">
      <h3 className="edit-purchase-heading">Edit Purchase</h3>
      <form className="edit-purchase-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label>Location</label>
            <input type="text" name="location" value={updatedPurchase.location} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label>Material ID</label>
            <input type="text" name="materialid" value={updatedPurchase.materialid} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label>Quantity</label>
            <input type="number" name="quantity" value={updatedPurchase.quantity} onChange={handleChange} />
          </div>
          
        </div>
        <button type="submit" className="edit-purchase-btn">Save Changes</button>
      </form>
    </div>
  );
};

export default EditPurchase;
